#include <stdio.h>
#include <stdlib.h>

typedef struct Node {
    int val;
    struct Node *left, *right;
} Node;

Node* newNode(int v) {
    Node* n = (Node*)malloc(sizeof(Node));
    n->val = v; n->left = n->right = NULL; return n;
}

int main() {
    int T; if (scanf("%d", &T)!=1) return 0;
    while (T--) {
        int N; scanf("%d", &N);
        Node **nodes = (Node**)malloc((N+1) * sizeof(Node*));
        int *hasParent = (int*)calloc(N+1, sizeof(int));
        for (int i=1;i<=N;i++) nodes[i] = newNode(i);
        for (int i=0;i<N-1;i++) {
            int p,c; char dir; scanf("%d %d %c", &p, &c, &dir);
            if (dir=='L') nodes[p]->left = nodes[c];
            else nodes[p]->right = nodes[c];
            hasParent[c] = 1;
        }
        int root = 1; while (root<=N && hasParent[root]) root++;
        // BFS
        Node **queue = (Node**)malloc((N+5) * sizeof(Node*));
        int front=0, rear=0;
        queue[rear++] = nodes[root];
        while (front < rear) {
            int levelSize = rear - front;
            for (int i=0;i<levelSize;i++) {
                Node *cur = queue[front++];
                printf("%d", cur->val);
                if (i+1<levelSize) printf(" ");
                if (cur->left)  queue[rear++] = cur->left;
                if (cur->right) queue[rear++] = cur->right;
            }
            printf("\n");
        }
        free(queue);
        free(nodes);
        free(hasParent);
    }
    return 0;
}

