import sys
from collections import deque

def solve():
    data = sys.stdin.read().strip().split()
    if not data:
        return
    it = iter(data)
    T = int(next(it))
    out_lines = []
    for _ in range(T):
        N = int(next(it))
        nodes = [None] * (N + 1)
        for i in range(1, N + 1):
            nodes[i] = [None, None]  # [left, right]
        has_parent = [False] * (N + 1)
        for _ in range(N - 1):
            p = int(next(it)); c = int(next(it)); d = next(it)
            if d == 'L':
                nodes[p][0] = c
            else:
                nodes[p][1] = c
            has_parent[c] = True
        root = 1
        while root <= N and has_parent[root]:
            root += 1
        q = deque([root])
        while q:
            level_sz = len(q)
            level_vals = []
            for _ in range(level_sz):
                cur = q.popleft()
                level_vals.append(str(cur))
                left, right = nodes[cur]
                if left is not None:
                    q.append(left)
                if right is not None:
                    q.append(right)
            out_lines.append(' '.join(level_vals))
    sys.stdout.write('\n'.join(out_lines))

if __name__ == "__main__":
    solve()

