  const N = Number(input[idx++]);
  const left = new Array(N + 1).fill(0);
  const right = new Array(N + 1).fill(0);
  const hasParent = new Array(N + 1).fill(false);
  for (let i = 0; i < N - 1; i++) {
    const p = Number(input[idx++]);
    const c = Number(input[idx++]);
    const dir = input[idx++];
    if (dir === 'L') left[p] = c; else right[p] = c;
    hasParent[c] = true;
  }
  let root = 1;
  while (root <= N && hasParent[root]) root++;
  const queue = [root];
  while (queue.length) {
    const levelSize = queue.length;
    const levelVals = [];
    for (let i = 0; i < levelSize; i++) {
      const cur = queue.shift();
      levelVals.push(cur);
      if (left[cur]) queue.push(left[cur]);
      if (right[cur]) queue.push(right[cur]);
    }
    output.push(levelVals.join(' '));
  }
}
